import{_ as i,o as r,c as s,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const u=JSON.parse('{"title":"Sponsored social","description":"","frontmatter":{"title":"Sponsored social"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-social/index.md","filePath":"docs/fr/advertisers/sponsored-social/index.md"}'),t={name:"docs/fr/advertisers/sponsored-social/index.md"};function o(d,e,n,p,l,c){return r(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="sponsored-social-retail-media" tabindex="-1">Sponsored Social (Retail Media) <a class="header-anchor" href="#sponsored-social-retail-media" aria-label="Permalink to &quot;Sponsored Social (Retail Media)&quot;">​</a></h1><p>Diffusez vos contenus publicitaires via les comptes sociaux de nos e-commerçants partenaires (Instagram, Facebook, TikTok).</p><div><a href="workflow" class="btn btn-primary mr-2">Voir le Process</a><a href="specs" class="btn btn-outline">Specs Techniques</a></div><hr><h2>Pourquoi ce levier est puissant ?</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;margin-bottom:40px;width:100%;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-soft);"><h3>🤝 Endorsement (Caution)</h3><p>Vous ne parlez pas en votre nom, mais via la voix d&#39;un e-commerçant aimé par sa communauté.</p><ul><li>Crédibilité accrue.</li><li>Contournement de la &quot;Banner Blindness&quot;.</li><li>Taux de conversion supérieur.</li></ul></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>🎯 Audience Affinitaire</h3><p>Touchez les followers de marques de niche (Beauté, Tech, Food...) directement dans leur feed.</p><div style="margin-top:15px;font-size:0.9em;color:var(--vp-c-text-2);"><em>Exemple : Une marque de croquettes ciblant les abonnés d&#39;une animalerie en ligne.</em></div></div><div style="border:2px solid var(--gi-accent);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>🚀 Amplification Média</h3><p>Nous utilisons le format <strong>Partnership Ads</strong>.</p><p>Vous sponsorisez le post du distributeur pour toucher une audience large, bien au-delà de ses simples abonnés organiques.</p></div></div><h2>Formats Disponibles</h2><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;min-width:200px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;text-align:center;background:var(--vp-c-bg-elv);"><div style="font-size:30px;margin-bottom:10px;">📸</div><strong>Social Post</strong><br><span>Photo ou Carrousel</span></div><div style="flex:1;min-width:200px;border:1px solid var(--gi-tint-green-text);border-radius:6px;padding:15px;text-align:center;background:var(--gi-tint-green-bg);"><div style="font-size:30px;margin-bottom:10px;">🎥</div><strong>Social Video</strong><br><span>Reels &amp; TikTok (Vertical)</span><br><em style="font-size:12px;color:var(--gi-tint-green-text);">Recommandé</em></div><div style="flex:1;min-width:200px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;text-align:center;background:var(--vp-c-bg-elv);"><div style="font-size:30px;margin-bottom:10px;">⏱️</div><strong>Story</strong><br><span>Format éphémère (24h)</span></div></div><h2>Pourquoi passer par getinside ?</h2><div style="display:flex;flex-direction:column;gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">⚡</div><div><h3>Activation à l&#39;échelle</h3><p>Ne perdez plus de temps à contacter les marques une par une. Lancez des campagnes simultanées sur plusieurs comptes retailers depuis une interface unique.</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🎯</div><div><h3>Donnée Retail (First Party)</h3><p>Le ciblage ne se base pas uniquement sur les &quot;intérêts&quot; sociaux, mais sur la <strong>clientèle réelle</strong> des e-commerçants. Touchez des acheteurs avérés.</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">⚙️</div><div><h3>Setup Technique Simplifié</h3><p>La configuration des &quot;Partnership Ads&quot; (Meta) ou &quot;Spark Ads&quot; (TikTok) est complexe. Nous guidons les éditeurs et vérifions les autorisations pour vous.</p></div></div></div>',10)])])}const x=i(t,[["render",o]]);export{u as __pageData,x as default};
